async (params, browser) => {
  // Open pull requests page
  await browser.open(`https://github.com/${params.repo}/pulls`)

  // Wait for PR list
  await browser.waitForSelector('.js-issue-row, .Box-row, [data-testid=\'pull-request-row\'], [aria-label=\'Pull Requests\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Extract PRs from DOM
  const result = await browser.evaluate(`const prs = []; const rows = document.querySelectorAll('.js-issue-row, .Box-row, [data-testid="pull-request-row"]'); for (let i = 0; i < Math.min(rows.length, 20); i++) { const row = rows[i]; const titleEl = row.querySelector('a[data-hovercard-type="pull_request"], a.Link--primary, a[id^="issue_"]'); const labels = Array.from(row.querySelectorAll('a.IssueLabel, a[data-name], .lh-default .label')).map(l => l.textContent.trim()); const authorEl = row.querySelector('a[data-hovercard-type="user"], .opened-by a'); const timeEl = row.querySelector('relative-time'); const href = titleEl ? (titleEl.getAttribute('href') || '') : ''; const numberMatch = href.match(/\/(\d+)$/); prs.push({ title: titleEl ? titleEl.textContent.trim() : '', number: numberMatch ? numberMatch[1] : '', labels: labels, author: authorEl ? authorEl.textContent.trim() : '', time: timeEl ? timeEl.getAttribute('datetime') || timeEl.textContent.trim() : '', url: titleEl ? (titleEl.href || ('https://github.com' + href)) : '' }); } const repoPath = window.location.pathname.replace(/\/pulls.*/, '').substring(1); return { repo: repoPath, result_count: prs.length, pull_requests: prs }`)

  return result
}
